class Solution {
    public List<Integer> findAllPeople(int n, int[][] meetings, int firstPerson) {
        List<Integer> people = new ArrayList<>();
        Set<Integer> visited = new HashSet<>();
        Queue<Integer> queue = new LinkedList<>();
        queue.offer(firstPerson);
        visited.add(firstPerson);
        while (!queue.isEmpty()) {
            int person = queue.poll();
            people.add(person);
            for (int[] meeting : meetings) {
                if (meeting[0] == person || meeting[1] == person) {
                    int otherPerson = meeting[0] == person ? meeting[1] : meeting[0];
                    if (!visited.contains(otherPerson)) {
                        visited.add(otherPerson);
                        queue.offer(otherPerson);
                    }
                }
            }
        }
        return people;
    }
}
